The quick and dirty implementation looks like this. Perhaps it will help someone else

```
void HttpServer::on_connect (
        std::istream& in,
        std::ostream& out,
        const std::string& foreign_ip,
        const std::string& local_ip,
        unsigned short foreign_port,
        unsigned short local_port,
        uint64
) {

    try
    {
        incoming_things incoming(foreign_ip, local_ip, foreign_port, local_port);
        outgoing_things outgoing;

        parse_http_request(in, incoming, get_max_content_length());
        read_body(in, incoming);

        if(incoming.path == "/video_feed"){
            ostringstream sout;

            out << "HTTP/1.1 " << outgoing.http_return << " " << outgoing.http_return_status << "\r\n";

            sout << "Cache-Control: " << "no-store, no-cache, must-revalidate, pre-check=0, post-check=0, max-age=0" << "\r\n";
            sout << "Connection: " << "close" << "\r\n";
            sout << "Content-type: " << "multipart/x-mixed-replace;boundary=--boundarydonotcross" << "\r\n\r\n";
            out << sout.str();

            std::vector<uchar> jpg_data;//buffer
            std::vector<int> param(2);
            param[0] = cv::IMWRITE_JPEG_QUALITY;
            param[1] = 80;//quality 0-100

            while(true) {
                cv::Mat mat_img = ui_image.clone();
                cv::imencode(".jpg", mat_img, jpg_data, param);
                std::string jpg_string(jpg_data.begin(), jpg_data.end());

                ostringstream sout2;
                sout2 << "--boundarydonotcross\r\n"
                      << "Content-type: image/jpeg\r\n"
                      << "Content-length: "+ to_string(jpg_string.length()) +"\r\n\r\n"
                      << jpg_string;

                out << sout2.str();
                dlib::sleep(50);
            }

        } else {
            ostringstream sout;

            sout << " <html> <body> "
                 << "<h1>Here I am</h1>"
                 << "<img id=\"videofield\" class=\"video\" src=\"/video_feed\">"
                 << "</body></html>";

            write_http_response(out, outgoing, sout.str());

        }
    }
    catch (http_parse_error& e)
    {
        write_http_response(out, e);
    }
    catch (std::exception& e)
    {
        write_http_response(out, e);
    }
};


```

